// Strict v3 env contract preflight. Fail fast with missing ENV NAMES only.
const config = {
  appUrl: String(process.env.APP_URL || '').trim(),
  webhookSecret: String(process.env.N8N_WEBHOOK_SECRET || '').trim(),
  anthropicApiKey: String(process.env.ANTHROPIC_API_KEY || '').trim(),
  adzunaAppId: String(process.env.ADZUNA_APP_ID || '').trim(),
  adzunaAppKey: String(process.env.ADZUNA_APP_KEY || '').trim(),
  jsearchApiKey: String(process.env.JSEARCH_API_KEY || '').trim(),
  joobleApiKey: String(process.env.JOOBLE_API_KEY || '').trim(),
  reedApiKey: String(process.env.REED_API_KEY || '').trim(),
  v3CanaryUserIds: String(process.env.V3_CANARY_USER_IDS || '').trim(),
  v3CanarySampleRate: String(process.env.V3_CANARY_SAMPLE_RATE || '0').trim(),
  v3JobCapPerUser: String(process.env.V3_JOB_CAP_PER_USER || '').trim(),
  v3TailorCapPerUser: String(process.env.V3_TAILOR_CAP_PER_USER || '').trim(),
  v3LlmPaceMs: String(process.env.V3_LLM_PACE_MS || '').trim(),
  v3MaxRetries: String(process.env.V3_MAX_RETRIES || '').trim(),
  v3RetryBaseMs: String(process.env.V3_RETRY_BASE_MS || '').trim(),
  v3RetryCapMs: String(process.env.V3_RETRY_CAP_MS || '').trim()
};

const required = {
  APP_URL: config.appUrl,
  N8N_WEBHOOK_SECRET: config.webhookSecret,
  ANTHROPIC_API_KEY: config.anthropicApiKey,
  ADZUNA_APP_ID: config.adzunaAppId,
  ADZUNA_APP_KEY: config.adzunaAppKey,
  JSEARCH_API_KEY: config.jsearchApiKey,
  JOOBLE_API_KEY: config.joobleApiKey,
  REED_API_KEY: config.reedApiKey,
  V3_JOB_CAP_PER_USER: config.v3JobCapPerUser,
  V3_TAILOR_CAP_PER_USER: config.v3TailorCapPerUser,
  V3_LLM_PACE_MS: config.v3LlmPaceMs,
  V3_MAX_RETRIES: config.v3MaxRetries,
  V3_RETRY_BASE_MS: config.v3RetryBaseMs,
  V3_RETRY_CAP_MS: config.v3RetryCapMs
};

const missing = Object.entries(required)
  .filter(([_, value]) => !String(value || '').trim())
  .map(([name]) => name);

if (missing.length > 0) {
  throw new Error('MISSING_ENV_NAMES:' + missing.join(','));
}

return [{
  json: {
    config: {
      ...config,
      v3CanarySampleRate: Number(config.v3CanarySampleRate || 0),
      v3JobCapPerUser: Number(config.v3JobCapPerUser),
      v3TailorCapPerUser: Number(config.v3TailorCapPerUser),
      v3LlmPaceMs: Number(config.v3LlmPaceMs),
      v3MaxRetries: Number(config.v3MaxRetries),
      v3RetryBaseMs: Number(config.v3RetryBaseMs),
      v3RetryCapMs: Number(config.v3RetryCapMs)
    }
  }
}];

const input = $input.first().json || {};
const config = input.config || {};
const runId = 'disc_v3_' + String($execution.id || Date.now());

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function parseJsonObject(text) {
  const raw = String(text || '');
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start < 0 || end <= start) return null;
  try {
    return JSON.parse(raw.slice(start, end + 1));
  } catch {
    return null;
  }
}

function parseJsonArray(text) {
  const raw = String(text || '');
  const start = raw.indexOf('[');
  const end = raw.lastIndexOf(']');
  if (start < 0 || end <= start) return null;
  try {
    const parsed = JSON.parse(raw.slice(start, end + 1));
    return Array.isArray(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

function slotIdForNow() {
  const now = new Date();
  const slotHour = Math.floor(now.getUTCHours() / 4) * 4;
  const slot = new Date(Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth(),
    now.getUTCDate(),
    slotHour,
    0,
    0,
    0
  ));
  return slot.toISOString();
}

function parseCsv(raw) {
  return String(raw || '').split(',').map((v) => v.trim()).filter(Boolean);
}

function sampleRate(raw) {
  const n = Number(raw);
  if (!Number.isFinite(n)) return 0;
  if (n >= 0 && n <= 1) return n;
  if (n > 1 && n <= 100) return n / 100;
  return 0;
}

function hashBucket(text) {
  let h = 0;
  const s = String(text || '');
  for (let i = 0; i < s.length; i += 1) {
    h = (h * 31 + s.charCodeAt(i)) >>> 0;
  }
  return h / 4294967296;
}

function isCanary(userId) {
  const allow = new Set(parseCsv(config.v3CanaryUserIds));
  if (allow.has(userId)) return true;
  const rate = sampleRate(config.v3CanarySampleRate);
  if (rate <= 0) return false;
  if (rate >= 1) return true;
  return hashBucket('disc-v3:' + userId) < rate;
}

function retryAfterMs(headers) {
  const raw = headers && typeof headers.get === 'function' ? String(headers.get('retry-after') || '').trim() : '';
  if (!raw) return null;
  const n = Number(raw);
  if (Number.isFinite(n) && n >= 0) return Math.floor(n * 1000);
  const ts = Date.parse(raw);
  if (Number.isNaN(ts)) return null;
  const d = ts - Date.now();
  return d > 0 ? d : 0;
}

function shouldRetry(status) {
  if (status === 429 || status === 529) return true;
  return status >= 500 && status <= 599;
}

async function withRetry(fn, meta) {
  const maxRetries = Math.max(0, Number(config.v3MaxRetries || 0));
  const base = Math.max(1, Number(config.v3RetryBaseMs || 250));
  const cap = Math.max(base, Number(config.v3RetryCapMs || 5000));
  let attempt = 0;
  let repeated429 = false;

  while (attempt <= maxRetries) {
    attempt += 1;
    try {
      const value = await fn();
      return { value, repeated429, attempts: attempt };
    } catch (error) {
      const status = Number(error && error.status ? error.status : 0);
      if (status === 429) repeated429 = true;
      const retriable = shouldRetry(status);
      if (!retriable || attempt > maxRetries) {
        const reason = retriable
          ? 'MAX_RETRIES_REACHED_' + String(status || 'NETWORK')
          : 'NON_RETRIABLE_' + String(status || 'NETWORK');
        const wrapped = new Error(reason);
        wrapped.status = status;
        wrapped.stage = meta && meta.stage ? meta.stage : 'unknown';
        wrapped.userId = meta && meta.userId ? meta.userId : null;
        wrapped.repeated429 = repeated429;
        throw wrapped;
      }
      const retryAfter = Number(error && error.retryAfterMs ? error.retryAfterMs : 0) || 0;
      const exp = Math.min(cap, base * Math.pow(2, attempt - 1));
      const jitter = Math.floor(Math.random() * Math.max(50, Math.floor(base / 2)));
      await sleep(Math.max(retryAfter, exp + jitter));
    }
  }

  throw new Error('MAX_RETRIES_EXITED_UNEXPECTEDLY');
}

async function appWebhook(type, data, extraHeaders = {}, meta = {}) {
  const url = String(config.appUrl || '').replace(//$/, '') + '/api/webhooks/n8n';
  return withRetry(async () => {
    const resp = await fetch(url, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': config.webhookSecret,
        'x-run-id': runId,
        ...extraHeaders
      },
      body: JSON.stringify({ type, runId, data })
    });
    if (!resp.ok) {
      const err = new Error('APP_WEBHOOK_' + type + '_FAILED');
      err.status = resp.status;
      err.retryAfterMs = retryAfterMs(resp.headers);
      throw err;
    }
    try {
      return await resp.json();
    } catch {
      return {};
    }
  }, meta);
}

async function anthropic(payload, meta) {
  return withRetry(async () => {
    const resp = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': config.anthropicApiKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify(payload)
    });
    if (!resp.ok) {
      const err = new Error('ANTHROPIC_FAILED');
      err.status = resp.status;
      err.retryAfterMs = retryAfterMs(resp.headers);
      throw err;
    }
    return resp.json();
  }, meta);
}

async function emitWorkflowError(stage, reasonCode, payload, userId) {
  const url = String(config.appUrl || '').replace(//$/, '') + '/api/webhooks/n8n';
  await fetch(url, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'x-webhook-secret': config.webhookSecret,
      'x-run-id': runId
    },
    body: JSON.stringify({
      type: 'workflow_error',
      runId,
      data: {
        workflowId: 'job-discovery-pipeline-v3',
        nodeName: stage,
        errorType: reasonCode,
        message: stage + ':' + reasonCode,
        payload: payload,
        userId: userId || undefined
      }
    })
  }).catch(() => null);
}

const slotId = slotIdForNow();
let lockId = null;

try {
  const acquire = await appWebhook('automation_lock_acquire', {
    runId,
    workflow: 'discovery_v3',
    slotId,
    ttlSeconds: 4 * 60 * 60
  }, {}, { stage: 'lock_acquire' });

  if (!acquire || !acquire.acquired) {
    return [{ json: { status: 'skipped_lock_not_acquired', runId, slotId } }];
  }
  lockId = acquire.lockId;

  const usersPayload = await appWebhook('fetch_active_users', { runId }, {}, { stage: 'fetch_active_users' });
  const users = Array.isArray(usersPayload && usersPayload.users) ? usersPayload.users : [];
  const canaryUsers = users.filter((u) => u && u.id && isCanary(String(u.id)));

  const summary = {
    status: 'ok',
    runId,
    slotId,
    usersSeen: users.length,
    usersCanary: canaryUsers.length,
    usersProcessed: 0,
    usersFailed: 0,
    persistedApplications: 0
  };

  for (const user of canaryUsers) {
    const userId = String(user.id || '').trim();
    if (!userId) continue;

    try {
      const jobsPayload = await appWebhook(
        'fetch_jobs_for_user',
        {
          user: {
            userId,
            targetTitles: Array.isArray(user.targetTitles) ? user.targetTitles : [],
            locations: Array.isArray(user.locations) ? user.locations : [],
            remotePreference: user.remotePreference || 'any',
            masterCvText: String(user.masterCvText || ''),
            subscriptionStatus: String(user.subscriptionStatus || 'free'),
            creditsRemaining: Number(user.creditsRemaining || 0)
          },
          sourceConfig: {
            adzunaAppId: config.adzunaAppId,
            adzunaAppKey: config.adzunaAppKey,
            jsearchApiKey: config.jsearchApiKey,
            joobleApiKey: config.joobleApiKey,
            reedApiKey: config.reedApiKey
          }
        },
        {},
        { stage: 'fetch_jobs_for_user', userId }
      );

      const jobs = Array.isArray(jobsPayload && jobsPayload.jobs) ? jobsPayload.jobs : [];
      const dedupe = new Set();
      const normalized = [];
      for (const job of jobs) {
        if (!job || typeof job !== 'object') continue;
        const title = String(job.title || '').trim();
        const description = String(job.description || '').trim();
        const source = String(job.source || 'manual').trim() || 'manual';
        const externalId = String(job.externalId || job.url || '').trim();
        if (!title || !description || !externalId) continue;
        const key = (source + ':' + externalId).toLowerCase();
        if (dedupe.has(key)) continue;
        dedupe.add(key);
        normalized.push({
          externalId,
          title,
          company: String(job.company || 'Unknown Company').trim() || 'Unknown Company',
          location: String(job.location || 'Not specified').trim() || 'Not specified',
          description,
          source,
          url: String(job.url || '').trim(),
          salary: job.salary || null,
          postedAt: job.postedAt || null,
          userId,
          masterCvText: String(user.masterCvText || '')
        });
      }

      const capped = normalized.slice(0, Math.max(0, Number(config.v3JobCapPerUser || 0)));
      if (capped.length === 0) {
        summary.usersProcessed += 1;
        continue;
      }

      const scoringPrompt = [
        'Return ONLY a JSON array:',
        '[{"idx":0,"compatibility_score":0-100,"ats_keywords":[],"matching_strengths":[],"gaps":[],"recommendation":"apply|stretch|skip"}]',
        'Candidate CV:',
        String(user.masterCvText || '').slice(0, 7000),
        'Jobs:',
        JSON.stringify(capped.map((job, idx) => ({ idx, title: job.title, company: job.company, description: job.description.slice(0, 2200) })))
      ].join('
');

      let scoredRows = null;
      const scoringPrimary = await anthropic({
        model: 'claude-3-5-haiku-20241022',
        max_tokens: 1400,
        temperature: 0,
        messages: [{ role: 'user', content: scoringPrompt }]
      }, { stage: 'score_batch_primary', userId });
      const scoringPrimaryText = scoringPrimary && scoringPrimary.content && scoringPrimary.content[0] ? scoringPrimary.content[0].text || '' : '';
      scoredRows = parseJsonArray(scoringPrimaryText);

      if (!Array.isArray(scoredRows)) {
        const scoringFallback = await anthropic({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 1800,
          temperature: 0,
          messages: [{ role: 'user', content: scoringPrompt }]
        }, { stage: 'score_batch_fallback', userId });
        const scoringFallbackText = scoringFallback && scoringFallback.content && scoringFallback.content[0] ? scoringFallback.content[0].text || '' : '';
        scoredRows = parseJsonArray(scoringFallbackText);
      }

      if (!Array.isArray(scoredRows)) {
        throw new Error('SCORING_PARSE_FAILURE');
      }

      const scoreByIdx = new Map();
      for (const row of scoredRows) {
        if (!row || typeof row !== 'object') continue;
        const idx = Number(row.idx);
        if (!Number.isInteger(idx)) continue;
        scoreByIdx.set(idx, {
          compatibilityScore: Number(row.compatibility_score || 0),
          atsKeywords: Array.isArray(row.ats_keywords) ? row.ats_keywords.slice(0, 12) : [],
          matchingStrengths: Array.isArray(row.matching_strengths) ? row.matching_strengths.slice(0, 6) : [],
          gaps: Array.isArray(row.gaps) ? row.gaps.slice(0, 6) : [],
          recommendation: String(row.recommendation || 'skip')
        });
      }

      const scoredJobs = capped.map((job, idx) => {
        const score = scoreByIdx.get(idx) || {
          compatibilityScore: 0,
          atsKeywords: [],
          matchingStrengths: [],
          gaps: [],
          recommendation: 'skip'
        };
        return {
          ...job,
          compatibilityScore: Math.max(0, Math.min(100, Number(score.compatibilityScore || 0))),
          atsKeywords: score.atsKeywords,
          matchingStrengths: score.matchingStrengths,
          gaps: score.gaps,
          recommendation: score.recommendation
        };
      });

      const threshold = 70;
      const tailorCap = Math.max(0, Number(config.v3TailorCapPerUser || 0));
      const candidates = scoredJobs.filter((j) => Number(j.compatibilityScore || 0) >= threshold).slice(0, tailorCap);
      const candidateSet = new Set(candidates.map((j) => (j.source + ':' + j.externalId).toLowerCase()));
      const outputApplications = [];

      for (const job of scoredJobs) {
        const key = (job.source + ':' + job.externalId).toLowerCase();
        if (!candidateSet.has(key)) {
          outputApplications.push({ ...job, tailoredCvMarkdown: null, coverLetterMarkdown: null, status: 'discovered' });
          continue;
        }

        await sleep(Math.max(0, Number(config.v3LlmPaceMs || 0)));

        const tailorPrompt = [
          'Return ONLY JSON:',
          '{"tailored_cv_markdown":"...","motivation_letter_markdown":"..."}',
          'Never fabricate candidate facts.',
          'ATS keywords:',
          JSON.stringify(job.atsKeywords || []),
          'Job:',
          String(job.title || '') + ' at ' + String(job.company || ''),
          String(job.description || '').slice(0, 3500),
          'Candidate CV:',
          String(user.masterCvText || '').slice(0, 7000)
        ].join('
');

        let tailorResp = null;
        let fallback429 = false;
        try {
          tailorResp = await anthropic({
            model: 'claude-sonnet-4-20250514',
            max_tokens: 2600,
            temperature: 0.1,
            messages: [{ role: 'user', content: tailorPrompt }]
          }, { stage: 'tailor_primary', userId });
        } catch (error) {
          fallback429 = Boolean(error && error.repeated429);
          if (!fallback429) throw error;
        }

        if (!tailorResp && fallback429) {
          tailorResp = await anthropic({
            model: 'claude-3-7-sonnet-20250219',
            max_tokens: 2600,
            temperature: 0.1,
            messages: [{ role: 'user', content: tailorPrompt }]
          }, { stage: 'tailor_fallback_429', userId });
        }

        const tailorText = tailorResp && tailorResp.content && tailorResp.content[0] ? tailorResp.content[0].text || '' : '';
        const tailored = parseJsonObject(tailorText);
        if (!tailored || typeof tailored !== 'object') {
          throw new Error('TAILORING_PARSE_FAILURE');
        }

        outputApplications.push({
          ...job,
          tailoredCvMarkdown: String(tailored.tailored_cv_markdown || ''),
          coverLetterMarkdown: String(tailored.motivation_letter_markdown || ''),
          status: 'tailored'
        });
      }

      const idempotencyKey = 'disc_v3:' + slotId + ':' + userId;
      await appWebhook(
        'new_applications',
        { userId, applications: outputApplications },
        { 'x-idempotency-key': idempotencyKey },
        { stage: 'persist_new_applications', userId }
      ).catch(async (error) => {
        await emitWorkflowError('persist_new_applications', 'PERSISTENCE_FAILED', {
          runId,
          slotId,
          userId,
          reason: String(error && error.message ? error.message : error)
        }, userId);
        throw new Error('PERSISTENCE_FAILED');
      });

      summary.usersProcessed += 1;
      summary.persistedApplications += outputApplications.length;
    } catch (error) {
      summary.usersFailed += 1;
      const reasonCode = String(error && error.message ? error.message : 'USER_PIPELINE_FAILED');
      await emitWorkflowError('user_pipeline', reasonCode, { runId, slotId, userId, reasonCode }, userId);
      if (reasonCode === 'PERSISTENCE_FAILED') {
        throw error;
      }
    }
  }

  return [{ json: summary }];
} catch (error) {
  const reasonCode = String(error && error.message ? error.message : 'DISCOVERY_V3_FAILED');
  await emitWorkflowError('pipeline', reasonCode, { runId, slotId, reasonCode }, null);
  throw error;
} finally {
  if (lockId) {
    await appWebhook('automation_lock_release', { runId, lockId }, {}, { stage: 'lock_release' }).catch(() => null);
  }
}
